     5→import { useShallow } from 'zustand/react/shallow';
     6→import type { ScreenProps } from '../../routes/Models';
     7→import { eventScreenViewV3, eventModalView, eventSelectContent } from '~/constants/functions';
     8→import { useRootStore } from '~/store';
     9→import { OrderDetailStatus, type TransactionType } from '../../services/models';
    10→import { getOrderDetail } from '../../services/services';
    11→import { formatToCurrency } from '../../utils/functions';
    12→import { moment } from '../../services/moment';
    13→import {
    14→  getTransactionGainType,
    15→  getFormattedPointsValue,
    16→  getFormattedHighlightText,
    17→  getFormattedPointsValueForMarketplace,
    18→  getPaymentTypeLabel,
    19→  getMarketplaceTitle,
    20→  getCleanedImageUrl,
    21→} from './utils';
    22→import type { MarketplaceContentData, MarketplaceItemData, MyOrdersDetailProps } from './Models';
    23→import { STATUS_COLORS } from './Models';
    24→import MyOrdersDetailView from './view';
    25→
    26→type ModalizeRefHandler = (ref: React.RefObject<PropsModalizeRef | null>) => void;
    27→
    28→interface UseMyOrdersDetailsReturn
    29→  extends Omit<MyOrdersDetailProps, 'modalizeRef' | 'modalizeRefInfo'> {
    30→  openReportProblem: ModalizeRefHandler;
    31→  closeReportProblem: ModalizeRefHandler;
    32→  openInfo: ModalizeRefHandler;
    33→  closeInfo: ModalizeRefHandler;
    34→}
    35→
    36→export function useMyOrdersDetails(
    37→  route: ScreenProps<'MyOrdersDetails'>['route'],
    38→): UseMyOrdersDetailsReturn {
    39→  const navigation = useNavigation();
    40→  const hasFocused = useRef(false);
    41→
    42→  const { orderDetail, orderDetailActions } = useRootStore(
    43→    useShallow((state) => ({
    44→      orderDetail: state.orderDetail,
    45→      orderDetailActions: state.orderDetailActions,
    46→    })),
    47→  );
    48→
    49→  const transactionId = route.params?.transactionId;
    50→  const passedType = route.params?.type;
    51→  const passedIcon = route.params?.icon;
    52→  const passedStatus = route.params?.status;
    53→  const passedOrigination = route.params?.origination;
    54→
    55→  useFocusEffect(
    56→    useCallback(() => {
    57→      if (!hasFocused.current) {
    58→        eventScreenViewV3(
    59→          'detalhe_pedido',
    60→          'hub_recompensas_spmais',
    61→          'monetizacao',
    62→          {
    63→            location_1: 'monetizacao',
    64→            location_2: 'hub_recompensas_spmais',
    65→            location_3: 'detalhe_pedido',
    66→          },
    67→        );
    68→        hasFocused.current = true;
    69→      }
    70→
    71→      if (transactionId) {
    72→        orderDetailActions.reset();
    73→        getOrderDetail({ transactionId });
    74→      }
    75→
    76→      return () => {
    77→        hasFocused.current = false;
    78→        orderDetailActions.reset();
    79→      };
    80→    }, [transactionId, orderDetailActions]),
    81→  );
    82→
    83→  const handleGoBack = useCallback(() => {
    84→    navigation.goBack();
    85→  }, [navigation]);
    86→
    87→  const openReportProblem = useCallback(
    88→    (modalizeRef: React.RefObject<PropsModalizeRef | null>) => {
    89→      eventSelectContent({
    90→        content_type: 'cta',
    91→        content_id: 'relatar_problema',
    92→        location_1: 'monetizacao',
    93→        location_2: 'hub_recompensas_spmais',
    94→        location_3: 'detalhe_pedido',
    95→      });
    96→
    97→      eventModalView({
    98→        content_id: 'contato_telefones',
    99→        location_1: 'monetizacao',
   100→        location_2: 'hub_recompensas_spmais',
   101→        location_3: 'detalhe_pedido',
   102→      });
   103→
   104→      modalizeRef.current?.open?.();
   105→    },
   106→    [],
   107→  );
   108→
   109→  const closeReportProblem = useCallback(
   110→    (modalizeRef: React.RefObject<PropsModalizeRef | null>) => {
   111→      modalizeRef.current?.close?.();
   112→    },
   113→    [],
   114→  );
   115→
   116→  const openInfo = useCallback(
   117→    (modalizeRefInfo: React.RefObject<PropsModalizeRef | null>) => {
   118→      modalizeRefInfo.current?.open?.();
   119→    },
   120→    [],
   121→  );
   122→
   123→  const closeInfo = useCallback(
   124→    (modalizeRefInfo: React.RefObject<PropsModalizeRef | null>) => {
   125→      modalizeRefInfo.current?.close?.();
   126→    },
   127→    [],
   128→  );
   129→
   130→  const isLoading = orderDetail.status === OrderDetailStatus.LOADING;
   131→  const hasError = orderDetail.status === OrderDetailStatus.ERROR;
   132→  const { height } = Dimensions.get('window');
   133→
   134→  const handleRetry = useCallback(() => {
   135→    if (transactionId) {
   136→      getOrderDetail({ transactionId });
   137→    }
   138→  }, [transactionId]);
   139→
   140→  const transaction = orderDetail.orderDetail;
   141→
   142→  const isValidTransactionType = (type: string | undefined): type is TransactionType => {
   143→    return type === 'CREDIT' || type === 'RESCUE' || type === 'EXPIRED' || type === 'REFUNDED';
   144→  };
   145→
   146→  const enrichedTransaction = useMemo(() => {
   147→    if (!transaction) return undefined;
   148→    return {
   149→      ...transaction,
   150→      type: isValidTransactionType(passedType) ? passedType : transaction.type,
   151→      icon: passedIcon || transaction.icon,
   152→      status: passedStatus || transaction.status,
   153→      details: {
   154→        ...transaction.details,
   155→        provider: passedOrigination || transaction.details?.provider || '',
   156→      },
   157→    };
   158→  }, [transaction, passedType, passedIcon, passedStatus, passedOrigination]);
   159→
   160→  const isCashback = passedType === 'RESCUE';
   161→
   162→  const processedData = useMemo(() => {
   163→    if (!enrichedTransaction) {
   164→      return {
   165→        cardTitle: '',
   166→        formattedPointsValue: '',
   167→        highlightText: '',
   168→        formattedCurrencyValue: '',
   169→        marketplaceContent: undefined,
   170→        showOrderNumber: false,
   171→        showStatus: false,
   172→        showValue: false,
   173→      };
   174→    }
   175→
   176→    const gainType = getTransactionGainType(enrichedTransaction);
   177→    const formattedCurrencyValue = formatToCurrency(enrichedTransaction.currencyValue);
   178→    const marketplaceValuePoints = enrichedTransaction?.marketplace?.valuePoints;
   179→    const formattedPointsValue =
   180→      marketplaceValuePoints !== undefined && marketplaceValuePoints !== null
   181→        ? `- ${getFormattedPointsValueForMarketplace(marketplaceValuePoints)}`
   182→        : getFormattedPointsValue(enrichedTransaction.amount, enrichedTransaction.type);
   183→    const marketplaceTitle = getMarketplaceTitle(enrichedTransaction);
   184→    const cardTitle = marketplaceTitle || enrichedTransaction.description || '';
   185→    const highlightText = getFormattedHighlightText(
   186→      enrichedTransaction.date,
   187→      gainType,
   188→      moment,
   189→    );
   190→
   191→    const isMarketplace = !!enrichedTransaction?.marketplace;
   192→    const marketplace = enrichedTransaction?.marketplace;
   193→
   194→    let marketplaceContent: MarketplaceContentData | undefined;
   195→    if (isMarketplace && marketplace) {
   196→      const firstPayment = marketplace.payments?.[0];
   197→      const firstOrder = marketplace.orders?.[0];
   198→      const vendorName = firstOrder?.vendor || '';
   199→
   200→      const items: MarketplaceItemData[] = [];
   201→      marketplace.orders?.forEach((order) => {
   202→        order.items?.forEach((item) => {
   203→          items.push({
   204→            name: item.name,
   205→            quantity: item.quantity,
   206→            valuePoints: getFormattedPointsValueForMarketplace(item.valuePoints),
   207→            imageUrl: item.imageUrl,
   208→            cleanedImageUrl: getCleanedImageUrl(item.imageUrl),
   209→          });
   210→        });
   211→      });
   212→
   213→      marketplaceContent = {
   214→        orderNumber: enrichedTransaction.id,
   215→        status: enrichedTransaction.status,
   216→        statusColor: enrichedTransaction.status
   217→          ? STATUS_COLORS[enrichedTransaction.status] || 'neutral'
   218→          : undefined,
   219→        paymentType: firstPayment ? getPaymentTypeLabel(firstPayment.paymentType) : undefined,
   220→        shippingValuePoints:
   221→          marketplace.shippingValuePoints !== undefined &&
   222→          marketplace.shippingValuePoints !== null
   223→            ? getFormattedPointsValueForMarketplace(marketplace.shippingValuePoints)
   224→            : undefined,
   225→        valuePoints:
   226→          marketplace.valuePoints !== undefined && marketplace.valuePoints !== null
   227→            ? getFormattedPointsValueForMarketplace(marketplace.valuePoints)
   228→            : undefined,
   229→        vendorName: vendorName || undefined,
   230→        items,
   231→      };
   232→    }
   233→
   234→    return {
   235→      cardTitle,
   236→      formattedPointsValue,
   237→      highlightText,
   238→      formattedCurrencyValue,
   239→      marketplaceContent,
   240→      showOrderNumber: !isMarketplace,
   241→      showStatus: !isMarketplace,
   242→      showValue: !isMarketplace,
   243→    };
   244→  }, [enrichedTransaction]);
   245→
   246→  return {
   247→    handleGoBack,
   248→    handleOpenReportProblem: () => {},
   249→    handleCloseReportProblem: () => {},
   250→    handleOpenInfo: () => {},
   251→    handleCloseInfo: () => {},
   252→    transaction: enrichedTransaction,
   253→    isLoading,
   254→    hasError,
   255→    handleRetry,
   256→    isCashback,
   257→    cardTitle: processedData.cardTitle,
   258→    formattedPointsValue: processedData.formattedPointsValue,
   259→    highlightText: processedData.highlightText,
   260→    formattedCurrencyValue: processedData.formattedCurrencyValue,
   261→    marketplaceContent: processedData.marketplaceContent,
   262→    showOrderNumber: processedData.showOrderNumber,
   263→    showStatus: processedData.showStatus,
   264→    showValue: processedData.showValue,
   265→    height,
   266→    openReportProblem,
   267→    closeReportProblem,
   268→    openInfo,
   269→    closeInfo,
   270→  };
   271→}
   272→
   273→const MyOrdersDetails = ({ route }: ScreenProps<'MyOrdersDetails'>) => {
   274→  const modalizeRef = useRef<PropsModalizeRef>(null);
   275→  const modalizeRefInfo = useRef<PropsModalizeRef>(null);
   276→
   277→  const {
   278→    openReportProblem,
   279→    closeReportProblem,
   280→    openInfo,
   281→    closeInfo,
   282→    ...hookData
   283→  } = useMyOrdersDetails(route);
   284→
   285→  return (
   286→    <MyOrdersDetailView
   287→      {...hookData}
   288→      modalizeRef={modalizeRef}
   289→      modalizeRefInfo={modalizeRefInfo}
   290→      handleOpenReportProblem={() => openReportProblem(modalizeRef)}
   291→      handleCloseReportProblem={() => closeReportProblem(modalizeRef)}
   292→      handleOpenInfo={() => openInfo(modalizeRefInfo)}
   293→      handleCloseInfo={() => closeInfo(modalizeRefInfo)}
   294→    />
   295→  );
   296→};
   297→
   298→export default MyOrdersDetails;
   299→

