     1→import { getOrderDetailApi, type OrderDetailRequestDto } from '../api/orderDetail.api';
     2→import { ANALYTICS_EVENTS } from '../constants';
     3→import { getOrderDetailFromResponse } from '../repository/orderDetail.repository';
     4→import { useRootStore } from '~/store';
     5→import {
     6→  OrderDetailStatus,
     7→} from '../models/orderDetail.model';
     8→import { eventServerResponse } from '~/constants/functions';
     9→import { getParticipantIdFromToken } from '../utils';
    10→
    11→interface GetOrderDetailPayload {
    12→  transactionId: string;
    13→  participantId?: string;
    14→}
    15→
    16→function handleOrderDetailSuccess(
    17→  orderDetail: ReturnType<typeof getOrderDetailFromResponse>,
    18→  transactionId: string,
    19→): void {
    20→  const { orderDetailActions } = useRootStore.getState();
    21→
    22→  if (orderDetail) {
    23→    orderDetailActions.setOrderDetail(orderDetail, transactionId);
    24→    eventServerResponse(ANALYTICS_EVENTS.ORDER_DETAIL_SUCCESS);
    25→  } else {
    26→    handleOrderDetailError();
    27→  }
    28→}
    29→
    30→function handleOrderDetailError(): void {
    31→  const { orderDetailActions } = useRootStore.getState();
    32→  orderDetailActions.setOrderDetailStatus(OrderDetailStatus.ERROR);
    33→  eventServerResponse(ANALYTICS_EVENTS.ORDER_DETAIL_ERROR);
    34→}
    35→
    36→export async function getOrderDetail(
    37→  payload: GetOrderDetailPayload,
    38→): Promise<void> {
    39→  const { orderDetailActions, orderDetail } = useRootStore.getState();
    40→
    41→  const isDifferentTransaction = orderDetail.transactionId !== payload.transactionId;
    42→  const isAlreadyLoading = orderDetail.status === OrderDetailStatus.LOADING;
    43→
    44→  if (isAlreadyLoading && !isDifferentTransaction) {
    45→    return;
    46→  }
    47→
    48→  if (isDifferentTransaction) {
    49→    orderDetailActions.reset();
    50→  }
    51→
    52→  orderDetailActions.setOrderDetailStatus(OrderDetailStatus.LOADING);
    53→
    54→  try {
    55→    const participantId =
    56→      payload?.participantId ?? (await getParticipantIdFromToken());
    57→
    58→    if (!participantId) {
    59→      handleOrderDetailError();
    60→      return;
    61→    }
    62→
    63→    const requestPayload: OrderDetailRequestDto = {
    64→      transactionId: payload.transactionId,
    65→      participantId,
    66→    };
    67→
    68→    const response = await getOrderDetailApi(requestPayload);
    69→    const orderDetailData = getOrderDetailFromResponse(response);
    70→
    71→    if (orderDetailData) {
    72→      handleOrderDetailSuccess(orderDetailData, payload.transactionId);
    73→      return;
    74→    }
    75→
    76→    handleOrderDetailError();
    77→  } catch {
    78→    handleOrderDetailError();
    79→  }
    80→}
    81→

